import { useNavigate } from "react-router-dom";


export default function CartPage() {
    const navigate = useNavigate();
    return (
        <div>
            <CartView>
                <B
                    onClick={() => navigate('/checkout')}
                    className="btn-primary checkout-btn"
                >
                    Proceder al Pago
                </B>
            </CartView>
        </div>
        
    )
}
